class Solution:
    def maximumLength(self, nums: List[int], k: int) -> int:
        n = len(nums)
        dp = [[0] * (k + 1) for _ in range(n)]

        for i in range(n):
            for j in range(k + 1):
                dp[i][j] = 1  # At least one element can be taken
                for l in range(i):
                    if nums[i] == nums[l]:
                        dp[i][j] = max(dp[i][j], dp[l][j] + 1)
                    else:
                        if j > 0:
                            dp[i][j] = max(dp[i][j], dp[l][j - 1] + 1)
        return max(max(row) for row in dp)
